import{_ as t,c as e,o as r,a2 as o}from"./chunks/framework.Sicmpk4x.js";const _=JSON.parse('{"title":"Overview","description":"","frontmatter":{"aside":false},"headers":[],"relativePath":"book/overview.md","filePath":"book/overview.md"}'),a={name:"book/overview.md"},d=o('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><p>This book contains a series of course projects which help students read all the code of <a href="https://github.com/yhzhang0128/egos-2000" target="_blank"> egos-2000</a>, a minimal teaching OS. There are 6 <strong>core projects</strong> covering most of the OS concepts for an undergraduate-level OS course (e.g., CS4411 at Cornell University).</p><table tabindex="0"><thead><tr><th>Core projects</th><th>OS concepts</th></tr></thead><tbody><tr><td>Hello, World!</td><td>memory, pointer, stack, user-level ISA</td></tr><tr><td>Non-preemptive Multithreading</td><td>context switch, thread, synchronization</td></tr><tr><td>Preemptive Scheduling</td><td>timer, interrupt handling, scheduling priority</td></tr><tr><td>System Call and Memory Protection</td><td>exception handling, control register, privilege level</td></tr><tr><td>Page Table Translation</td><td>RISC-V Sv32 address translation, process</td></tr><tr><td>File System</td><td>inode, file, directory, virtualization</td></tr></tbody></table><p>And there are 3 <strong>advanced projects</strong> covering more OS concepts for a master-level OS course (e.g., CS5411 at Cornell University).</p><table tabindex="0"><thead><tr><th>Advanced projects</th><th>OS concepts</th></tr></thead><tbody><tr><td>SD Card Driver</td><td>serial bus, memory-mapped I/O</td></tr><tr><td>Ethernet and UDP</td><td>data link layer, IP layer, transportation layer</td></tr><tr><td>Multi-core and Atomic Instruction</td><td>atomic memory operation, spinlock, critical section</td></tr></tbody></table><p>Now, let&#39;s get hands dirty and have fun!</p>',6),i=[d];function n(s,c,l,h,p,v){return r(),e("div",null,i)}const g=t(a,[["render",n]]);export{_ as __pageData,g as default};
